    core_set(&v_step, CoreValue::from("nodeName"), v_trimmed.clone())?;
    core_set(&v_step, CoreValue::from("program"), v_program.clone())?;
    core_set(&v_step, CoreValue::from("options"), v_opts.clone())?;
